INSERT INTO questions (exam_id, subject_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'Which of the following is the correct formula to estimate the annual volume (cum) required for a landfill? {where, P = Population, m = average mass(kg) of solid waste collected per person per year, V = annual volume, p = compacted fill density (kg/m³)}', 'Pm/p', 'Pmp', 'P', '', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'Read the following statements regarding drinking water parameters and choose the correct option. Statements: 1. When protection against viral infection is required, concentration of free residual chlorine should be minimum 0.5mg/l in the drinking water. 2. The maximum limit of Sulphate (as SO₄) may be extended (in absence of alternate source) to 400 mg/l, only if the Magnesium does not exceed 30mg/l, in the drinking water.', 'Both statements are incorrect.', 'Statement 1 is correct and statement 2 is incorrect.', 'Both statements are correct.', 'Statement 1 is incorrect and statement 2 is correct.', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'Arrange the following Air Pollution Control Devices in their increasing order of efficiency. A. Fabric Filter B. Electrostatic Precipitator C. Wet Scrubber D. Gravitational Settling Chamber', 'B, D, C, A', 'C, A, D, B', 'A, B, C, D', 'D, C, B, A', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'For areas of moderate sizes, such as involved for branch sewers, the maximum daily sewage flows can be expressed as', '2 X average daily flow', '4 X average daily flow', '0.5 X average daily flow', '6 X average daily flow', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'Choose the most appropriate range of the ratio of ultimate BOD (Bio- chemical oxygen demand) to the COD (Chemical Oxygen Demand) of a waste water, so that it may be considered as fully biodegradable.', '1.2 to 1.5', '0.9 to 1.0', '0.1 to 0.2', '2.2 to 2.5', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'The upper layer of lake water through which sunlight can penetrate is known as:', 'Euphotic Zone', 'Littoral Zone', 'Benthic Zone', 'Oligotrophic Zone', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'Calculate the BOD₅ (kg/day) of the waste water of an industry, if the population equivalent of the industrial waste water is 3750 and average standard BOD₅ of domestic sewage is 0.08 kg/day/person.', '5000', '46875', '300', '480', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'Which of the following is/are the disadvantage(s) of interceptor related to house drainage in buildings? 1. Cleaning through the inspection arm of the interceptor trap is not easy. 2. Foul gases of the public sewer cannot pass through the interceptor. 3. Interceptor itself forms an obstruction to the normal flow of sewage.', 'Only 1', 'Only 2', 'Only 3', '1 and 3 only', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'Which of the following is the incorrectly matched pair of material of sewer and its non- scouring velocity (cm/sec)?', 'Ordinary Brick-Lined Sewers - 150 to 250', 'Cement Concrete Sewers - 250 to 300', 'Cast Iron Sewer Pipes - 60 to 120', 'Vitrified Tile - 450 to 500', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'dd2eab18-a6c2-4636-a005-1f9ea9aef419', 2023, 'Paper-II', 'The forces whose lines of action do not lie in one plane and they do not meet at one point are known as', 'Non- coplanar and Non- concurrent forces', 'Non- coplanar and concurrent forces', 'Coplanar and Non- concurrent forces', 'Coplanar and concurrent forces', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'dd2eab18-a6c2-4636-a005-1f9ea9aef419', 2023, 'Paper-II', 'The resultant of two concurrent coplanar forces P & Q is R. If the direction of force Q is reversed then resultant of the forces become S, then (R² + S²) will be equal to ______.', '(P² + Q²)²', '4(P²+Q²)', '2(P²- Q²)', '2(P²+Q²)', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'dd2eab18-a6c2-4636-a005-1f9ea9aef419', 2023, 'Paper-II', 'Read the following statements regarding equilibrium of coplanar and concurrent forces and choose the correct option. Statements: 1. If two forces acting on a body are represented in magnitude and direction by the two sides of a triangle taken in order, then their resultant is given by the third side of the triangle taken in the opposite order. 2. If three forces acting on a particle keep it in equilibrium, then each force is proportional to the cosine of the angle between the other two forces.', 'Both statements are incorrect.', 'Statement 1 is correct and statement 2 is incorrect.', 'Both statements are correct.', 'Statement 1 is incorrect and statement 2 is correct.', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'dd2eab18-a6c2-4636-a005-1f9ea9aef419', 2023, 'Paper-II', 'Find the incorrectly matched pair of moment of inertia and its formula related to the given rectangular lamina.', 'I_y'' - (db³)/3', 'I_x - (bd³)/12', 'I_y - (db³)/12', 'I_x'' - (bd³)/2', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'dd2eab18-a6c2-4636-a005-1f9ea9aef419', 2023, 'Paper-II', 'A steel flat 150mm wide and 20mm thick is subjected to a tensile stress of 200N/mm². Find the strain induced in the steel flat. (Take Young''s modulus of elasticity = 2×10⁵ N/mm²)', '0.01', '0.001', '0.150', '0.00075', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'dd2eab18-a6c2-4636-a005-1f9ea9aef419', 2023, 'Paper-II', 'A cantilever beam of a 2m span has a left end A as a free end, whereas the right end B is the fixed supported end. It is acted upon by a point load of 10kN at the free end. The maximum bending moment will occur at', 'point A''', 'the midpoint of the span', '0.5m from point A''', 'point B''', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'aee3c24f-8b41-461f-8e64-e9544a04c1b6', 2023, 'Paper-II', 'Following IS 1200, match the items under List 1 (Type of work) with those under List 2 (nearest decimal value of measurement). Use codes in lists for matching. P) Length dimension in earthwork (in m units) Q) Length dimension in earthwork done by mechanical means, when dimension is more than 25 m (in m units). R) Thickness of slab in concrete works (in m units). S) Area of steel work (in m² units)', 'P-3,Q-4,R-2,S-1', 'P-2,Q-3,R-1,S-4', 'P-4,Q-1,R-2,S-3', 'P-2,Q-1,R-4,S-3', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'dd2eab18-a6c2-4636-a005-1f9ea9aef419', 2023, 'Paper-II', 'Arrange the following points on stress - strain curve of tension test in chronological order (from the earliest to the latest) of their appearance. A. Fracture Point B. Yield Point C. Proportional Limit D. Elastic Limit', 'D, B, A, C', 'C, D, B, A', 'A, C, D, B', 'B, A, C, D', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'dd2eab18-a6c2-4636-a005-1f9ea9aef419', 2023, 'Paper-II', 'Which of the following statements regarding Euler''s Assumptions is/are correct? Statements: 1. The length of column is very large as compared to cross- sectional dimensions. 2. The cross- section of the column is uniform throughout its length.', 'Both statements are incorrect.', 'Statement 1 is correct and statement 2 is incorrect.', 'Both statements are correct.', 'Statement 1 is incorrect and statement 2 is correct.', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'dd2eab18-a6c2-4636-a005-1f9ea9aef419', 2023, 'Paper-II', 'Match the items under List 1 (Type of Beam & Loading Conditions) with those under List 2 (Value of maximum deflection) and choose the correct option. P. Cantilever Beam of span L subjected to point load "P" at free end. Q. Cantilever Beam of span L subjected to uniformly distributed load of intensity "p" per unit length on entire span R. Simply Supported beam of span L subjected to point load "P" at mid span S. Simply Supported beam of span L subjected to uniformly distributed load of intensity "p" per unit length on entire span', 'P-4,Q-1,R-2,S-3', 'P-2,Q-4,R-1,S-3', 'P-3,Q-1,R-4,S-2', 'P-4,Q-3,R-1,S-2', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'The scale of a map is represented as 1 : 50000. The distance between two points A and B is measured as 10 cm in the map. The actual distance between the two points in the field is:', '0.5 km', '5 km', '50 km', '500 m', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'Consider the electromagnetic spectrum used in remote sensing. Match the items under List 1 (Wave length values) with those under List 2 (Name of region in electromagnetic spectrum). P. 0.4 to 0.7 μm Q. 0.7 to 3 μm R. 3 to 14 μm S. 1mm to 1m', 'P-3,Q-1,R-4,S-2', 'P-2,Q-3,R-4,S-1', 'P-4,Q-1,R-2,S-3', 'P-4,Q-3,R-1,S-2', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'Consider the following statements based on stadia tacheometry: P. Stadia tacheometry is based on readings taken against the stadia cross hairs and two forms of stadia method (fixed hair and movable hair) are used. Q. Fixed hair stadia method uses a special diaphragm that enable to change the distance between the cross hairs, the intercept is kept constant even though the distance varies. R. Movable hair method, wherein the distance between the stadia hairs is kept constant, the intercept varies as the distance varies. Identify the correct statements and choose the correct option.', 'P only', 'Q only', 'Q and R only', 'P, Q, and R', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'The bearings to four stations taken using a prismatic compass are given below in Table. Covert them into reduced bearings and arrange the points in the increasing order of magnitude of reduced bearing values. Point P:275°30'', Q:165°30'', R:192°00'', S:328°30''', 'Q, R, S, P', 'R, Q, S, P', 'S, R, P, Q', 'P, Q, S, R', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'Among the different corrections applied to a chain surveying identify the correction which is not always negative.', 'Correction due to wrong alignment', 'Correction due to slope', 'Correction due to pull', 'Correction due to sag', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '3f275622-18e3-40ce-a134-ec660b48190c', 2023, 'Paper-II', 'In a total station survey work, the leveling of the total station and exact centering at a station are respectively done by using:', 'Optical plummet and Automatic compensator', 'Tripod legs and Standards (A- frame)', 'Optical plummet, tripod legs and circular bubble', 'Tripod legs, Levelling Foot screws and Optical plummet', 4, NULL, 'medium')
